  invalid: [
    {
      code: "Promise.resolve(1).then((v) => v);",
      errors: [{ messageId: "thenChain" }],
    },
    {
      code: "fetch('/x').then((r) => r.json());",
      errors: [{ messageId: "thenChain" }],
    },
    {
      code: "foo.then(ok, err);",
      errors: [{ messageId: "thenChain" }],
    },
    {
      code: "await foo.then((v) => v);",
      errors: [{ messageId: "thenChain" }],
    },
    {
      code: "a.b.c.then(x => x);",
      errors: [{ messageId: "thenChain" }],
    },
  ],
});

